import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageSquare, X, Send } from 'lucide-react';

const FloatingButton = () => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="fixed bottom-8 right-8 z-[60]">
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.8, y: 20 }}
            className="mb-4 w-72 bg-charcoal border border-gold p-6 rounded-lg shadow-2xl"
          >
            <h3 className="font-cinzel text-gold mb-2 text-lg">Inquiry Hub</h3>
            <p className="text-xs text-ivory/60 mb-4 font-montserrat uppercase tracking-tighter">Request a callback or message us</p>
            <form className="space-y-3" onSubmit={(e) => e.preventDefault()}>
              <input 
                className="w-full bg-charcoal border border-ivory/20 p-2 text-sm focus:border-gold outline-none transition-all"
                placeholder="Full Name"
              />
              <input 
                className="w-full bg-charcoal border border-ivory/20 p-2 text-sm focus:border-gold outline-none transition-all"
                placeholder="Phone Number"
              />
              <button className="w-full gold-gradient text-charcoal font-bold py-2 text-sm uppercase tracking-widest hover:brightness-110 transition-all flex items-center justify-center rounded">
                Send Request <Send size={14} className="ml-2" />
              </button>
            </form>
          </motion.div>
        )}
      </AnimatePresence>

      <motion.button
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 gold-gradient rounded-full flex items-center justify-center shadow-lg text-charcoal"
      >
        {isOpen ? <X size={28} /> : <MessageSquare size={28} />}
      </motion.button>
    </div>
  );
};

export default FloatingButton;
